  ('judicial-57112235-moex-00697', 'judicial-57112235', 'judicial-57112235-moex-110-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '美國犯罪學家赫胥（Travis Hirschi）的社會控制理論（Social Control Theory；社會鍵理論 Social BondTheory），是最具影響力的犯罪學理論之一。有關此理論的內容，下列敘述何者正確？', '["認為人性是道德或是利他的動物", "社會鍵的要素包含依附（attachment）、監督（supervision）及信念（belief）", "奉獻或責任感（commitment）是社會鍵的要素之一", "赫胥認為社會鍵的各個要素之間是互相獨立、沒有關聯的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "603b48f24109", "answer_pdf_sha1": "9e5d7a84b2b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
