  ('judicial-57112235-moex-00703', 'judicial-57112235', 'judicial-57112235-moex-110-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '有關毒品犯罪之敘述，下列何者錯誤？', '["依我國毒品危害防制條例之規定，大麻列入第三級毒品", "會對使用者產生成癮性、依賴性及戒斷症狀之藥物，常屬於醫學及藥理學上的物質", "毒品犯罪者常衍生出竊盜、販毒、搶奪等犯罪行為", "安非他命是中樞神經興奮劑 20750"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "603b48f24109", "answer_pdf_sha1": "9e5d7a84b2b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
